#!/usr/bin/env bash
set -euo pipefail

# Founder OS Installer
# Usage: ./install.sh [--verify] [--skip-notion] [--reset]

# ── Colors & Output ──────────────────────────────────────────────
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
BOLD='\033[1m'
NC='\033[0m' # No Color

ok()   { echo -e "  ${GREEN}✓${NC} $1"; }
warn() { echo -e "  ${YELLOW}⚠${NC} $1"; }
fail() { echo -e "  ${RED}✗${NC} $1"; }
info() { echo -e "  ${BLUE}→${NC} $1"; }
header() { echo -e "\n${BOLD}$1${NC}"; }

# ── Flag Parsing ─────────────────────────────────────────────────
VERIFY_ONLY=false
SKIP_NOTION=false
RESET=false

for arg in "$@"; do
  case $arg in
    --verify)      VERIFY_ONLY=true ;;
    --skip-notion) SKIP_NOTION=true ;;
    --reset)       RESET=true ;;

