// lib/manifest.js
// Manifest read/write and SHA-256 checksum computation
'use strict';

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const MANIFEST_PATH = '.founderOS/manifest.json';
const VERSION_PATH = '.founderOS/version.json';

function computeChecksum(filePath) {
  const content = fs.readFileSync(filePath);
  return 'sha256:' + crypto.createHash('sha256').update(content).digest('hex');
}

function readManifest(baseDir) {
  const manifestFile = path.join(baseDir, MANIFEST_PATH);
  if (!fs.existsSync(manifestFile)) return null;
  return JSON.parse(fs.readFileSync(manifestFile, 'utf8'));
}

function writeManifest(baseDir, manifest) {
  const manifestFile = path.join(baseDir, MANIFEST_PATH);
  fs.writeFileSync(manifestFile, JSON.stringify(manifest, null, 2) + '\n');
}

function readVersion(baseDir) {
  const versionFile = path.join(baseDir, VERSION_PATH);
  if (!fs.existsSync(versionFile)) return null;

{
  "name": "founder-os",
  "version": "1.0.0",
  "description": "AI-powered business automation for founders — installs into any Claude Code project",
  "license": "MIT",
  "author": {
    "name": "Founder OS",
    "email": "contact@founderos.dev"
  },
  "repository": {
    "type": "git",
    "url": "https://github.com/thecloudtips/founder-os-dist.git"
  },
  "keywords": ["claude-code", "ai", "automation", "founder", "business"],
  "bin": {
    "founder-os": "bin/founder-os.js"
  },
  "files": [
    "bin/",
    "lib/",
    "template/",
    "README.md",
    "LICENSE",
    "CHANGELOG.md"
  ],
  "engines": {
    "node": ">=18.0.0"
  }
}

